     1→import 'package:flutter/widgets.dart';
     2→import 'package:obers_ui/src/components/buttons/oi_button.dart';
     3→import 'package:obers_ui/src/foundation/oi_app.dart';
     4→import 'package:obers_ui/src/foundation/theme/oi_theme.dart';
     5→import 'package:obers_ui/src/primitives/interaction/oi_tappable.dart';
     6→
     7→/// A group of buttons displayed inline with a connected visual appearance.
     8→///
     9→/// Buttons in a group share their borders so that adjacent buttons appear
    10→/// joined together. In [segmented] mode exactly one button is active at a time
    11→/// (the one at [selectedIndex]); tapping any button calls [onSelected] with
    12→/// its index.
    13→///
    14→/// ```dart
    15→/// OiButtonGroup(
    16→///   buttons: [
    17→///     OiButton.outline(label: 'Day'),
    18→///     OiButton.outline(label: 'Week'),
    19→///     OiButton.outline(label: 'Month'),
    20→///   ],
    21→///   segmented: true,
    22→///   selectedIndex: _tab,
    23→///   onSelected: (i) => setState(() => _tab = i),
    24→/// )
    25→/// ```
    26→///
    27→/// {@category Components}
    28→class OiButtonGroup extends StatelessWidget {
    29→  /// Creates an [OiButtonGroup].
    30→  const OiButtonGroup({
    31→    required this.buttons,
    32→    this.orientation = Axis.horizontal,
    33→    this.segmented = false,
    34→    this.selectedIndex,
    35→    this.onSelected,
    36→    super.key,
    37→  });
    38→
    39→  /// The buttons to render inside the group.
    40→  final List<OiButton> buttons;
    41→
    42→  /// Whether buttons are arranged horizontally or vertically.
    43→  final Axis orientation;
    44→
    45→  /// When `true`, tapping a button marks it as selected and calls [onSelected].
    46→  final bool segmented;
    47→
    48→  /// The index of the currently selected button in [segmented] mode.
    49→  final int? selectedIndex;
    50→
    51→  /// Called with the tapped button's index when [segmented] is `true`.
    52→  final ValueChanged<int>? onSelected;
    53→
    54→  @override
    55→  Widget build(BuildContext context) {
    56→    final count = buttons.length;
    57→    if (count == 0) return const SizedBox.shrink();
    58→
    59→    final items = List<Widget>.generate(count, (i) {
    60→      return _GroupButtonItem(
    61→        button: buttons[i],
    62→        index: i,
    63→        count: count,
    64→        orientation: orientation,
    65→        segmented: segmented,
    66→        selected: segmented && selectedIndex == i,
    67→        onSelected: onSelected,
    68→      );
    69→    });
    70→
    71→    if (orientation == Axis.horizontal) {
    72→      return Row(mainAxisSize: MainAxisSize.min, children: items);
    73→    } else {
    74→      return Column(mainAxisSize: MainAxisSize.min, children: items);
    75→    }
    76→  }
    77→}
    78→
    79→// ── Internal per-item widget ──────────────────────────────────────────────
    80→
    81→class _GroupButtonItem extends StatelessWidget {
    82→  const _GroupButtonItem({
    83→    required this.button,
    84→    required this.index,
    85→    required this.count,
    86→    required this.orientation,
    87→    required this.segmented,
    88→    required this.selected,
    89→    required this.onSelected,
    90→  });
    91→
    92→  final OiButton button;
    93→  final int index;
    94→  final int count;
    95→  final Axis orientation;
    96→  final bool segmented;
    97→  final bool selected;
    98→  final ValueChanged<int>? onSelected;
    99→
   100→  @override
   101→  Widget build(BuildContext context) {
   102→    final radius = context.components.button?.borderRadius ?? context.radius.sm;
   103→
   104→    // Compute per-corner radii so the group looks connected.
   105→    final BorderRadius borderRadius;
   106→    if (count == 1) {
   107→      borderRadius = radius;
   108→    } else if (orientation == Axis.horizontal) {
   109→      if (index == 0) {
   110→        borderRadius = BorderRadius.only(
   111→          topLeft: radius.topLeft,
   112→          bottomLeft: radius.bottomLeft,
   113→        );
   114→      } else if (index == count - 1) {
   115→        borderRadius = BorderRadius.only(
   116→          topRight: radius.topRight,
   117→          bottomRight: radius.bottomRight,
   118→        );
   119→      } else {
   120→        borderRadius = BorderRadius.zero;
   121→      }
   122→    } else {
   123→      // vertical
   124→      if (index == 0) {
   125→        borderRadius = BorderRadius.only(
   126→          topLeft: radius.topLeft,
   127→          topRight: radius.topRight,
   128→        );
   129→      } else if (index == count - 1) {
   130→        borderRadius = BorderRadius.only(
   131→          bottomLeft: radius.bottomLeft,
   132→          bottomRight: radius.bottomRight,
   133→        );
   134→      } else {
   135→        borderRadius = BorderRadius.zero;
   136→      }
   137→    }
   138→
   139→    // In segmented mode, selected = primary fill, others = ghost with border.
   140→    final OiButtonVariant effectiveVariant;
   141→    if (segmented) {
   142→      effectiveVariant =
   143→          selected ? OiButtonVariant.primary : OiButtonVariant.ghost;
   144→    } else {
   145→      effectiveVariant = button.variant;
   146→    }
   147→
   148→    final bgColor = _bgColor(context, effectiveVariant);
   149→    final fgColor = _fgColor(context, effectiveVariant);
   150→    final density = OiDensityScope.of(context);
   151→    final height = _buttonHeight(density);
   152→    final hPad = _hPadding(context);
   153→
   154→    // Build border: for connected group, share the edge between neighbours.
   155→    final border = _buildBorder(context, effectiveVariant);
   156→
   157→    final content = button.label != null
   158→        ? Text(
   159→            button.label!,
   160→            style: TextStyle(
   161→              fontSize: _fontSize(),
   162→              fontWeight: FontWeight.w500,
   163→              color: fgColor,
   164→              height: 1,
   165→            ),
   166→            maxLines: 1,
   167→            overflow: TextOverflow.ellipsis,
   168→          )
   169→        : (button.icon != null
   170→            ? Icon(button.icon, size: _iconSize(), color: fgColor)
   171→            : const SizedBox.shrink());
   172→
   173→    final isEnabled = button.enabled;
   174→    final tapCallback = segmented
   175→        ? (isEnabled ? () => onSelected?.call(index) : null)
   176→        : (isEnabled ? button.onTap : null);
   177→
   178→    return OiTappable(
   179→      onTap: tapCallback,
   180→      enabled: isEnabled,
   181→      child: Container(
   182→        height: height,
   183→        padding: EdgeInsets.symmetric(horizontal: hPad),
   184→        decoration: BoxDecoration(
   185→          color: bgColor,
   186→          borderRadius: borderRadius,
   187→          border: border,
   188→        ),
   189→        child: Center(child: content),
   190→      ),
   191→    );
   192→  }
   193→
   194→  Color _bgColor(BuildContext context, OiButtonVariant variant) {
   195→    final c = context.colors;
   196→    switch (variant) {
   197→      case OiButtonVariant.primary:
   198→        return c.primary.base;
   199→      case OiButtonVariant.secondary:
   200→        return c.accent.base;
   201→      case OiButtonVariant.outline:
   202→      case OiButtonVariant.ghost:
   203→        return const Color(0x00000000);
   204→      case OiButtonVariant.destructive:
   205→        return c.error.base;
   206→      case OiButtonVariant.soft:
   207→        return c.primary.muted;
   208→    }
   209→  }
   210→
   211→  Color _fgColor(BuildContext context, OiButtonVariant variant) {
   212→    final c = context.colors;
   213→    switch (variant) {
   214→      case OiButtonVariant.primary:
   215→        return c.primary.foreground;
   216→      case OiButtonVariant.secondary:
   217→        return c.accent.foreground;
   218→      case OiButtonVariant.outline:
   219→      case OiButtonVariant.ghost:
   220→        return c.text;
   221→      case OiButtonVariant.destructive:
   222→        return c.error.foreground;
   223→      case OiButtonVariant.soft:
   224→        return c.primary.base;
   225→    }
   226→  }
   227→
   228→  Border? _buildBorder(BuildContext context, OiButtonVariant variant) {
   229→    if (variant != OiButtonVariant.outline &&
   230→        variant != OiButtonVariant.ghost &&
   231→        !segmented) {
   232→      return null;
   233→    }
   234→    final borderColor = context.colors.border;
   235→    final side = BorderSide(color: borderColor);
   236→
   237→    if (count == 1) {
   238→      return Border.all(color: borderColor);
   239→    }
   240→
   241→    if (orientation == Axis.horizontal) {
   242→      // For horizontal groups: left border only on first, right border on last,
   243→      // internal items share a border so we only draw left for non-first.
   244→      if (index == 0) {
   245→        return Border(top: side, bottom: side, left: side);
   246→      } else if (index == count - 1) {
   247→        return Border(top: side, bottom: side, left: side, right: side);
   248→      } else {
   249→        return Border(top: side, bottom: side, left: side);
   250→      }
   251→    } else {
   252→      // Vertical: top border only on first, internal share borders.
   253→      if (index == 0) {
   254→        return Border(top: side, left: side, right: side);
   255→      } else if (index == count - 1) {
   256→        return Border(top: side, left: side, right: side, bottom: side);
   257→      } else {
   258→        return Border(top: side, left: side, right: side);
   259→      }
   260→    }
   261→  }
   262→
   263→  double _buttonHeight(OiDensity density) {
   264→    switch (button.size) {
   265→      case OiButtonSize.small:
   266→        switch (density) {
   267→          case OiDensity.comfortable:
   268→            return 28;
   269→          case OiDensity.compact:
   270→            return 24;
   271→          case OiDensity.dense:
   272→            return 20;
   273→        }
   274→      case OiButtonSize.medium:
   275→        switch (density) {
   276→          case OiDensity.comfortable:
   277→            return 36;
   278→          case OiDensity.compact:
   279→            return 32;
   280→          case OiDensity.dense:
   281→            return 28;
   282→        }
   283→      case OiButtonSize.large:
   284→        switch (density) {
   285→          case OiDensity.comfortable:
   286→            return 44;
   287→          case OiDensity.compact:
   288→            return 40;
   289→          case OiDensity.dense:
   290→            return 36;
   291→        }
   292→    }
   293→  }
   294→
   295→  double _iconSize() {
   296→    switch (button.size) {
   297→      case OiButtonSize.small:
   298→        return 14;
   299→      case OiButtonSize.medium:
   300→        return 16;
   301→      case OiButtonSize.large:
   302→        return 18;
   303→    }
   304→  }
   305→
   306→  double _fontSize() {
   307→    switch (button.size) {
   308→      case OiButtonSize.small:
   309→        return 12;
   310→      case OiButtonSize.medium:
   311→        return 14;
   312→      case OiButtonSize.large:
   313→        return 16;
   314→    }
   315→  }
   316→
   317→  double _hPadding(BuildContext context) {
   318→    final sp = context.spacing;
   319→    switch (button.size) {
   320→      case OiButtonSize.small:
   321→        return sp.sm;
   322→      case OiButtonSize.medium:
   323→        return sp.md;
   324→      case OiButtonSize.large:
   325→        return sp.lg;
   326→    }
   327→  }
   328→}
