     7→/// A button that toggles between selected and unselected states.
     8→///
     9→/// When [selected] is `true` the button renders with a filled primary style.
    10→/// When [selected] is `false` it renders as a ghost/outline button. Tapping
    11→/// calls [onChanged] with the opposite of [selected].
    12→///
    13→/// ```dart
    14→/// OiToggleButton(
    15→///   label: 'Bold',
    16→///   selected: _bold,
    17→///   onChanged: (v) => setState(() => _bold = v),
    18→/// )
    19→/// ```
    20→///
    21→/// {@category Components}
    22→class OiToggleButton extends StatelessWidget {
    23→  /// Creates an [OiToggleButton].
    24→  const OiToggleButton({
    25→    required this.selected,
    26→    required this.semanticLabel,
    27→    this.label,
    28→    this.icon,
    29→    this.onChanged,
    30→    this.size = OiButtonSize.medium,
    31→    this.enabled = true,
    32→    super.key,
    33→  });
    34→
    35→  /// Accessibility label announced by screen readers.
    36→  final String semanticLabel;
    37→
    38→  /// Optional text label.
    39→  final String? label;
    40→
    41→  /// Optional icon displayed alongside or instead of [label].
    42→  final IconData? icon;
    43→
    44→  /// Whether this button is in the selected / active state.
    45→  final bool selected;
    46→
    47→  /// Called when the button is tapped with the new selected value.
    48→  final ValueChanged<bool>? onChanged;
    49→
    50→  /// The size tier.
    51→  final OiButtonSize size;
    52→
    53→  /// Whether the button responds to interactions.
    54→  final bool enabled;
    55→
    56→  double _buttonHeight(OiDensity density) {
    57→    switch (size) {
    58→      case OiButtonSize.small:
    59→        switch (density) {
    60→          case OiDensity.comfortable:
    61→            return 28;
    62→          case OiDensity.compact:
    63→            return 24;
    64→          case OiDensity.dense:
    65→            return 20;
    66→        }
    67→      case OiButtonSize.medium:
    68→        switch (density) {
    69→          case OiDensity.comfortable:
    70→            return 36;
    71→          case OiDensity.compact:
    72→            return 32;
    73→          case OiDensity.dense:
    74→            return 28;
    75→        }
    76→      case OiButtonSize.large:
    77→        switch (density) {
    78→          case OiDensity.comfortable:
    79→            return 44;
    80→          case OiDensity.compact:
    81→            return 40;
    82→          case OiDensity.dense:
    83→            return 36;
    84→        }
    85→    }
    86→  }
    87→
    88→  double _iconSize() {
    89→    switch (size) {
    90→      case OiButtonSize.small:
    91→        return 14;
    92→      case OiButtonSize.medium:
    93→        return 16;
    94→      case OiButtonSize.large:
    95→        return 18;
    96→    }
    97→  }
    98→
    99→  double _fontSize() {
   100→    switch (size) {
   101→      case OiButtonSize.small:
   102→        return 12;
   103→      case OiButtonSize.medium:
   104→        return 14;
   105→      case OiButtonSize.large:
   106→        return 16;
   107→    }
   108→  }
   109→
   110→  @override
   111→  Widget build(BuildContext context) {
   112→    final density = OiDensityScope.of(context);
   113→    final colors = context.colors;
   114→    final spacing = context.spacing;
   115→    final radius = context.radius;
   116→
   117→    final height = _buttonHeight(density);
   118→
   119→    final bgColor = selected ? colors.primary.base : const Color(0x00000000);
   120→    final fgColor = selected ? colors.primary.foreground : colors.text;
   121→    final border = selected
   122→        ? null
   123→        : Border.all(color: colors.border);
   124→    final borderRadius =
   125→        context.components.button?.borderRadius ?? radius.sm;
   126→
   127→    double hPad;
   128→    switch (size) {
   129→      case OiButtonSize.small:
   130→        hPad = spacing.sm;
   131→      case OiButtonSize.medium:
   132→        hPad = spacing.md;
   133→      case OiButtonSize.large:
   134→        hPad = spacing.lg;
   135→    }
   136→
   137→    Widget content;
   138→    if (icon != null && label != null) {
   139→      content = Row(
   140→        mainAxisSize: MainAxisSize.min,
   141→        children: [
   142→          Icon(icon, size: _iconSize(), color: fgColor),
   143→          SizedBox(width: spacing.xs),
   144→          Text(
   145→            label!,
   146→            style: TextStyle(
   147→              fontSize: _fontSize(),
   148→              fontWeight: FontWeight.w500,
   149→              color: fgColor,
   150→              height: 1,
   151→            ),
   152→          ),
   153→        ],
   154→      );
   155→    } else if (icon != null) {
   156→      content = Icon(icon, size: _iconSize(), color: fgColor);
   157→    } else {
   158→      content = Text(
   159→        label ?? '',
   160→        style: TextStyle(
   161→          fontSize: _fontSize(),
   162→          fontWeight: FontWeight.w500,
   163→          color: fgColor,
   164→          height: 1,
   165→        ),
   166→        maxLines: 1,
   167→        overflow: TextOverflow.ellipsis,
   168→      );
   169→    }
   170→
   171→    return OiTappable(
   172→      onTap: enabled ? () => onChanged?.call(!selected) : null,
   173→      enabled: enabled,
   174→      child: Container(
   175→        height: height,
   176→        padding: EdgeInsets.symmetric(horizontal: hPad),
   177→        decoration: BoxDecoration(
   178→          color: bgColor,
   179→          borderRadius: borderRadius,
   180→          border: border,
   181→        ),
   182→        child: Center(child: content),
   183→      ),
   184→    );
   185→  }
   186→}
