     4→/// The rendering mode for an [OiDiffView].
     5→///
     6→/// {@category Components}
     7→enum OiDiffMode {
     8→  /// Added and removed lines shown in separate left/right columns.
     9→  sideBySide,
    10→
    11→  /// All lines interleaved in a single column with color coding.
    12→  unified,
    13→}
    14→
    15→/// A single line in a diff, annotated with its change type.
    16→///
    17→/// {@category Components}
    18→class OiDiffLine {
    19→  /// Creates an [OiDiffLine].
    20→  const OiDiffLine({
    21→    required this.content,
    22→    this.lineNumber,
    23→    this.added = false,
    24→    this.removed = false,
    25→    this.unchanged = false,
    26→  });
    27→
    28→  /// The text content of this line.
    29→  final String content;
    30→
    31→  /// The optional line number in the source file.
    32→  final int? lineNumber;
    33→
    34→  /// Whether this line was added.
    35→  final bool added;
    36→
    37→  /// Whether this line was removed.
    38→  final bool removed;
    39→
    40→  /// Whether this line is unchanged context.
    41→  final bool unchanged;
    42→}
    43→
    44→/// A diff viewer that renders a list of [OiDiffLine] entries.
    45→///
    46→/// Supports [OiDiffMode.unified] (all lines interleaved, default) and
    47→/// [OiDiffMode.sideBySide] (removed on left, added on right). Added lines
    48→/// receive a green background; removed lines receive a red background.
    49→///
    50→/// {@category Components}
    51→class OiDiffView extends StatelessWidget {
    52→  /// Creates an [OiDiffView].
    53→  const OiDiffView({
    54→    required this.lines,
    55→    this.mode = OiDiffMode.unified,
    56→    this.showLineNumbers = true,
    57→    super.key,
    58→  });
    59→
    60→  /// The diff lines to display.
    61→  final List<OiDiffLine> lines;
    62→
    63→  /// The rendering mode.
    64→  final OiDiffMode mode;
    65→
    66→  /// Whether to render line numbers.
    67→  final bool showLineNumbers;
    68→
    69→  @override
    70→  Widget build(BuildContext context) {
    71→    if (mode == OiDiffMode.sideBySide) {
    72→      return _buildSideBySide(context);
    73→    }
    74→    return _buildUnified(context);
    75→  }
    76→
    77→  Widget _buildUnified(BuildContext context) {
    78→    final colors = context.colors;
    79→    const monoStyle = TextStyle(fontFamily: 'monospace', fontSize: 13, height: 1.5);
    80→
    81→    return Container(
    82→      decoration: BoxDecoration(
    83→        color: colors.surfaceSubtle,
    84→        borderRadius: BorderRadius.circular(6),
    85→        border: Border.all(color: colors.border),
    86→      ),
    87→      child: Column(
    88→        mainAxisSize: MainAxisSize.min,
    89→        crossAxisAlignment: CrossAxisAlignment.stretch,
    90→        children: lines.map((line) {
    91→          final bg = line.added
    92→              ? colors.success.base.withValues(alpha: 0.12)
    93→              : line.removed
    94→                  ? colors.error.base.withValues(alpha: 0.12)
    95→                  : null;
    96→
    97→          final prefix = line.added
    98→              ? '+ '
    99→              : line.removed
   100→                  ? '- '
   101→                  : '  ';
   102→
   103→          final textColor = line.added
   104→              ? colors.success.base
   105→              : line.removed
   106→                  ? colors.error.base
   107→                  : colors.text;
   108→
   109→          Widget row = Padding(
   110→            padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 1),
   111→            child: Row(
   112→              crossAxisAlignment: CrossAxisAlignment.start,
   113→              children: [
   114→                if (showLineNumbers && line.lineNumber != null)
   115→                  Text(
   116→                    '${line.lineNumber!}'.padLeft(4),
   117→                    style: monoStyle.copyWith(color: colors.textMuted),
   118→                  ),
   119→                if (showLineNumbers && line.lineNumber != null)
   120→                  const SizedBox(width: 12),
   121→                Text(
   122→                  '$prefix${line.content}',
   123→                  style: monoStyle.copyWith(color: textColor),
   124→                ),
   125→              ],
   126→            ),
   127→          );
   128→
   129→          if (bg != null) {
   130→            row = ColoredBox(color: bg, child: row);
   131→          }
   132→
   133→          return row;
   134→        }).toList(),
   135→      ),
   136→    );
   137→  }
   138→
   139→  Widget _buildSideBySide(BuildContext context) {
   140→    final colors = context.colors;
   141→    const monoStyle = TextStyle(fontFamily: 'monospace', fontSize: 13, height: 1.5);
   142→
   143→    final removed = lines.where((l) => l.removed || l.unchanged).toList();
   144→    final added = lines.where((l) => l.added || l.unchanged).toList();
   145→    final maxLen = removed.length > added.length ? removed.length : added.length;
   146→
   147→    Widget column(List<OiDiffLine> colLines, {required bool isAddedSide}) {
   148→      return Expanded(
   149→        child: Column(
   150→          mainAxisSize: MainAxisSize.min,
   151→          crossAxisAlignment: CrossAxisAlignment.stretch,
   152→          children: List.generate(maxLen, (i) {
   153→            if (i >= colLines.length) return const SizedBox(height: 22);
   154→            final line = colLines[i];
   155→            final bg = isAddedSide && line.added
   156→                ? colors.success.base.withValues(alpha: 0.12)
   157→                : !isAddedSide && line.removed
   158→                    ? colors.error.base.withValues(alpha: 0.12)
   159→                    : null;
   160→            final textColor = isAddedSide && line.added
   161→                ? colors.success.base
   162→                : !isAddedSide && line.removed
   163→                    ? colors.error.base
   164→                    : colors.text;
   165→
   166→            Widget cell = Padding(
   167→              padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 1),
   168→              child: Text(
   169→                line.content,
   170→                style: monoStyle.copyWith(color: textColor),
   171→              ),
   172→            );
   173→            if (bg != null) cell = ColoredBox(color: bg, child: cell);
   174→            return cell;
   175→          }),
   176→        ),
   177→      );
   178→    }
   179→
   180→    return Container(
   181→      decoration: BoxDecoration(
   182→        color: colors.surfaceSubtle,
   183→        borderRadius: BorderRadius.circular(6),
   184→        border: Border.all(color: colors.border),
   185→      ),
   186→      child: Row(
   187→        crossAxisAlignment: CrossAxisAlignment.start,
   188→        children: [
   189→          column(removed, isAddedSide: false),
   190→          Container(width: 1, color: colors.border),
   191→          column(added, isAddedSide: true),
   192→        ],
   193→      ),
   194→    );
   195→  }
   196→}
