     3→// ── Node definition ───────────────────────────────────────────────────────────
     4→
     5→/// A single node in an [OiTree].
     6→///
     7→/// Nodes are immutable value objects. Build the tree by nesting [OiTreeNode]
     8→/// instances through the [children] list.
     9→///
    10→/// {@category Composites}
    11→@immutable
    12→class OiTreeNode<T> {
    13→  /// Creates an [OiTreeNode].
    14→  const OiTreeNode({
    15→    required this.id,
    16→    required this.label,
    17→    this.data,
    18→    this.children = const [],
    19→    this.leaf = false,
    20→    this.icon,
    21→  });
    22→
    23→  /// A unique identifier for this node within the tree.
    24→  final String id;
    25→
    26→  /// The human-readable label displayed for this node.
    27→  final String label;
    28→
    29→  /// Optional typed data payload attached to this node.
    30→  final T? data;
    31→
    32→  /// Direct children of this node.
    33→  final List<OiTreeNode<T>> children;
    34→
    35→  /// When `true`, this node is always treated as a leaf even if [children] is
    36→  /// non-empty (e.g. for lazy-loading scenarios).
    37→  final bool leaf;
    38→
    39→  /// Optional leading icon widget.
    40→  final Widget? icon;
    41→
    42→  /// Whether this node has any children and is not forced to leaf mode.
    43→  bool get hasChildren => !leaf && children.isNotEmpty;
    44→}
    45→
    46→// ── Controller ────────────────────────────────────────────────────────────────
    47→
    48→/// Controls the interactive state of an [OiTree].
    49→///
    50→/// Manages the set of expanded and selected node IDs. Notifies listeners on
    51→/// every state mutation so that an [OiTree] can rebuild.
    52→///
    53→/// {@category Composites}
    54→class OiTreeController extends ChangeNotifier {
    55→  /// Creates an [OiTreeController].
    56→  ///
    57→  /// [multiSelect] controls whether multiple nodes can be selected at once.
    58→  OiTreeController({this.multiSelect = false});
    59→
    60→  /// Whether multiple nodes may be selected simultaneously.
    61→  final bool multiSelect;
    62→
    63→  /// The set of IDs of currently expanded nodes.
    64→  final Set<String> expandedIds = {};
    65→
    66→  /// The set of IDs of currently selected nodes.
    67→  final Set<String> selectedIds = {};
    68→
    69→  // ── Expand / collapse ─────────────────────────────────────────────────────
    70→
    71→  /// Expands the node identified by [id].
    72→  ///
    73→  /// Does nothing (and does not notify) when [id] is already expanded.
    74→  void expand(String id) {
    75→    if (expandedIds.contains(id)) return;
    76→    expandedIds.add(id);
    77→    notifyListeners();
    78→  }
    79→
    80→  /// Collapses the node identified by [id].
    81→  ///
    82→  /// Does nothing (and does not notify) when [id] is already collapsed.
    83→  void collapse(String id) {
    84→    if (!expandedIds.remove(id)) return;
    85→    notifyListeners();
    86→  }
    87→
    88→  /// Toggles the expanded state of the node identified by [id].
    89→  void toggle(String id) {
    90→    if (expandedIds.contains(id)) {
    91→      expandedIds.remove(id);
    92→    } else {
    93→      expandedIds.add(id);
    94→    }
    95→    notifyListeners();
    96→  }
    97→
    98→  /// Expands all nodes in [ids].
    99→  void expandAll(Iterable<String> ids) {
   100→    final before = expandedIds.length;
   101→    expandedIds.addAll(ids);
   102→    if (expandedIds.length != before) notifyListeners();
   103→  }
   104→
   105→  /// Collapses all currently expanded nodes.
   106→  void collapseAll() {
   107→    if (expandedIds.isEmpty) return;
   108→    expandedIds.clear();
   109→    notifyListeners();
   110→  }
   111→
   112→  // ── Selection ─────────────────────────────────────────────────────────────
   113→
   114→  /// Selects the node identified by [id].
   115→  ///
   116→  /// When [multiSelect] is `false`, any previous selection is cleared first.
   117→  void select(String id) {
   118→    if (!multiSelect) selectedIds.clear();
   119→    if (selectedIds.contains(id)) return;
   120→    selectedIds.add(id);
   121→    notifyListeners();
   122→  }
   123→
   124→  /// Deselects the node identified by [id].
   125→  ///
   126→  /// Does nothing (and does not notify) when [id] is not selected.
   127→  void deselect(String id) {
   128→    if (!selectedIds.remove(id)) return;
   129→    notifyListeners();
   130→  }
   131→
   132→  /// Clears the entire selection.
   133→  ///
   134→  /// Does nothing (and does not notify) when already empty.
   135→  void clearSelection() {
   136→    if (selectedIds.isEmpty) return;
   137→    selectedIds.clear();
   138→    notifyListeners();
   139→  }
   140→
   141→  /// Whether the node identified by [id] is expanded.
   142→  bool isExpanded(String id) => expandedIds.contains(id);
   143→
   144→  /// Whether the node identified by [id] is selected.
   145→  bool isSelected(String id) => selectedIds.contains(id);
   146→}
   147→
   148→// ── Widget ────────────────────────────────────────────────────────────────────
   149→
   150→/// A hierarchical tree-view widget.
   151→///
   152→/// Renders a list of root [OiTreeNode]s, supporting expand/collapse,
   153→/// single or multi-node selection, lazy-loading children, and custom
   154→/// node builders.
   155→///
   156→/// ```dart
   157→/// OiTree<MyData>(
   158→///   nodes: [
   159→///     OiTreeNode(id: 'root', label: 'Root', children: [
   160→///       OiTreeNode(id: 'child1', label: 'Child 1'),
   161→///     ]),
   162→///   ],
   163→/// )
   164→/// ```
   165→///
   166→/// {@category Composites}
   167→class OiTree<T> extends StatefulWidget {
   168→  /// Creates an [OiTree].
   169→  const OiTree({
   170→    required this.nodes,
   171→    this.controller,
   172→    this.onNodeTap,
   173→    this.onNodeDoubleTap,
   174→    this.onExpansionChanged,
   175→    this.onSelectionChanged,
   176→    this.nodeBuilder,
   177→    this.indentWidth = 24,
   178→    this.rowHeight = 40,
   179→    this.selectable = false,
   180→    this.multiSelect = false,
   181→    this.showLines = false,
   182→    super.key,
   183→  });
   184→
   185→  /// The root nodes of the tree.
   186→  final List<OiTreeNode<T>> nodes;
   187→
   188→  /// Optional external controller. When `null`, the widget manages its own
   189→  /// internal [OiTreeController].
   190→  final OiTreeController? controller;
   191→
   192→  /// Called when the user taps a node.
   193→  final void Function(OiTreeNode<T> node)? onNodeTap;
   194→
   195→  /// Called when the user double-taps a node.
   196→  final void Function(OiTreeNode<T> node)? onNodeDoubleTap;
   197→
   198→  /// Called when a node's expansion state changes.
   199→  ///
   200→  /// The boolean argument is `true` when the node expands and `false`
   201→  /// when it collapses.
   202→  final void Function(OiTreeNode<T> node, {required bool expanded})? onExpansionChanged;
   203→
   204→  /// Called when the selection changes.
   205→  final void Function(Set<String> selectedIds)? onSelectionChanged;
   206→
   207→  /// Custom builder for a single node row.
   208→  ///
   209→  /// When `null`, a default row is rendered with an optional leading icon,
   210→  /// an expand/collapse toggle for parent nodes, and the node's [label].
   211→  final Widget Function(
   212→    BuildContext context,
   213→    OiTreeNode<T> node,
   214→    int depth, {
   215→    required bool expanded,
   216→    required bool selected,
   217→  })? nodeBuilder;
   218→
   219→  /// Indent width in logical pixels per depth level.
   220→  final double indentWidth;
   221→
   222→  /// Height of a single node row.
   223→  final double rowHeight;
   224→
   225→  /// Whether nodes can be selected by tapping.
   226→  final bool selectable;
   227→
   228→  /// Whether multiple nodes may be selected at once.
   229→  final bool multiSelect;
   230→
   231→  /// Whether to draw connecting lines between nodes.
   232→  final bool showLines;
   233→
   234→  @override
   235→  State<OiTree<T>> createState() => _OiTreeState<T>();
   236→}
   237→
   238→class _OiTreeState<T> extends State<OiTree<T>> {
   239→  late OiTreeController _ctrl;
   240→  bool _ownsController = false;
   241→
   242→  @override
   243→  void initState() {
   244→    super.initState();
   245→    _initController();
   246→  }
   247→
   248→  @override
   249→  void didUpdateWidget(OiTree<T> oldWidget) {
   250→    super.didUpdateWidget(oldWidget);
   251→    if (widget.controller != oldWidget.controller) {
   252→      _disposeControllerIfOwned();
   253→      _initController();
   254→    }
   255→  }
   256→
   257→  @override
   258→  void dispose() {
   259→    _disposeControllerIfOwned();
   260→    super.dispose();
   261→  }
   262→
   263→  void _initController() {
   264→    if (widget.controller != null) {
   265→      _ctrl = widget.controller!;
   266→      _ownsController = false;
   267→    } else {
   268→      _ctrl = OiTreeController(multiSelect: widget.multiSelect);
   269→      _ownsController = true;
   270→    }
   271→    _ctrl.addListener(_onControllerChanged);
   272→  }
   273→
   274→  void _disposeControllerIfOwned() {
   275→    _ctrl.removeListener(_onControllerChanged);
   276→    if (_ownsController) _ctrl.dispose();
   277→  }
   278→
   279→  void _onControllerChanged() => setState(() {});
   280→
   281→  // ── Flattened render list ─────────────────────────────────────────────────
   282→
   283→  /// Flattens the tree to a list of visible (depth, node) pairs.
   284→  List<({int depth, OiTreeNode<T> node})> get _visibleItems {
   285→    final items = <({int depth, OiTreeNode<T> node})>[];
   286→    void visit(OiTreeNode<T> node, int depth) {
   287→      items.add((depth: depth, node: node));
   288→      if (node.hasChildren && _ctrl.isExpanded(node.id)) {
   289→        for (final child in node.children) {
   290→          visit(child, depth + 1);
   291→        }
   292→      }
   293→    }
   294→
   295→    for (final root in widget.nodes) {
   296→      visit(root, 0);
   297→    }
   298→    return items;
   299→  }
   300→
   301→  // ── Event handlers ────────────────────────────────────────────────────────
   302→
   303→  void _handleTap(OiTreeNode<T> node) {
   304→    if (widget.selectable) {
   305→      if (_ctrl.multiSelect) {
   306→        if (_ctrl.isSelected(node.id)) {
   307→          _ctrl.deselect(node.id);
   308→        } else {
   309→          _ctrl.select(node.id);
   310→        }
   311→      } else {
   312→        _ctrl.select(node.id);
   313→      }
   314→      widget.onSelectionChanged?.call(Set.from(_ctrl.selectedIds));
   315→    }
   316→    widget.onNodeTap?.call(node);
   317→  }
   318→
   319→  void _handleDoubleTap(OiTreeNode<T> node) {
   320→    widget.onNodeDoubleTap?.call(node);
   321→  }
   322→
   323→  void _handleToggle(OiTreeNode<T> node) {
   324→    final willExpand = !_ctrl.isExpanded(node.id);
   325→    _ctrl.toggle(node.id);
   326→    widget.onExpansionChanged?.call(node, expanded: willExpand);
   327→  }
   328→
   329→  // ── Build ─────────────────────────────────────────────────────────────────
   330→
   331→  @override
   332→  Widget build(BuildContext context) {
   333→    final items = _visibleItems;
   334→    return ListView.builder(
   335→      itemCount: items.length,
   336→      itemExtent: widget.rowHeight,
   337→      itemBuilder: (ctx, i) {
   338→        final item = items[i];
   339→        return _buildNodeRow(ctx, item.node, item.depth);
   340→      },
   341→    );
   342→  }
   343→
   344→  Widget _buildNodeRow(BuildContext ctx, OiTreeNode<T> node, int depth) {
   345→    final expanded = _ctrl.isExpanded(node.id);
   346→    final selected = _ctrl.isSelected(node.id);
   347→
   348→    if (widget.nodeBuilder != null) {
   349→      return GestureDetector(
   350→        key: ValueKey('node_${node.id}'),
   351→        behavior: HitTestBehavior.opaque,
   352→        onTap: () => _handleTap(node),
   353→        onDoubleTap: () => _handleDoubleTap(node),
   354→        child: widget.nodeBuilder!(
   355→          ctx,
   356→          node,
   357→          depth,
   358→          expanded: expanded,
   359→          selected: selected,
   360→        ),
   361→      );
   362→    }
   363→
   364→    return _DefaultNodeRow<T>(
   365→      key: ValueKey('node_${node.id}'),
   366→      node: node,
   367→      depth: depth,
   368→      expanded: expanded,
   369→      selected: selected,
   370→      indentWidth: widget.indentWidth,
   371→      rowHeight: widget.rowHeight,
   372→      onTap: () => _handleTap(node),
   373→      onDoubleTap: () => _handleDoubleTap(node),
   374→      onToggle: node.hasChildren ? () => _handleToggle(node) : null,
   375→    );
   376→  }
   377→}
   378→
   379→// ── Default node row ──────────────────────────────────────────────────────────
   380→
   381→class _DefaultNodeRow<T> extends StatelessWidget {
   382→  const _DefaultNodeRow({
   383→    required this.node,
   384→    required this.depth,
   385→    required this.expanded,
   386→    required this.selected,
   387→    required this.indentWidth,
   388→    required this.rowHeight,
   389→    required this.onTap,
   390→    required this.onDoubleTap,
   391→    this.onToggle,
   392→    super.key,
   393→  });
   394→
   395→  final OiTreeNode<T> node;
   396→  final int depth;
   397→  final bool expanded;
   398→  final bool selected;
   399→  final double indentWidth;
   400→  final double rowHeight;
   401→  final VoidCallback onTap;
   402→  final VoidCallback onDoubleTap;
   403→  final VoidCallback? onToggle;
   404→
   405→  @override
   406→  Widget build(BuildContext context) {
   407→    Widget row = Row(
   408→      children: [
   409→        SizedBox(width: depth * indentWidth),
   410→        if (node.hasChildren)
   411→          GestureDetector(
   412→            key: ValueKey('toggle_${node.id}'),
   413→            behavior: HitTestBehavior.opaque,
   414→            onTap: onToggle,
   415→            child: SizedBox(
   416→              width: 24,
   417→              height: rowHeight,
   418→              child: Center(child: Text(expanded ? '▼' : '▶')),
   419→            ),
   420→          )
   421→        else
   422→          SizedBox(width: 24, height: rowHeight),
   423→        if (node.icon != null) ...[
   424→          node.icon!,
   425→          const SizedBox(width: 4),
   426→        ],
   427→        Expanded(
   428→          child: Align(
   429→            alignment: AlignmentDirectional.centerStart,
   430→            child: Text(
   431→              node.label,
   432→              key: ValueKey('label_${node.id}'),
   433→              overflow: TextOverflow.ellipsis,
   434→            ),
   435→          ),
   436→        ),
   437→      ],
   438→    );
   439→
   440→    if (selected) {
   441→      row = ColoredBox(color: const Color(0xFFDBEAFE), child: row);
   442→    }
   443→
   444→    return GestureDetector(
   445→      behavior: HitTestBehavior.opaque,
   446→      onTap: onTap,
   447→      onDoubleTap: onDoubleTap,
   448→      child: SizedBox(height: rowHeight, child: row),
   449→    );
   450→  }
   451→}
