   243→  // ── Grouped display ───────────────────────────────────────────────────────
   244→
   245→  Map<String?, List<OiCommand>> get _grouped {
   246→    final groups = <String?, List<OiCommand>>{};
   247→    for (final cmd in _filteredCommands) {
   248→      groups.putIfAbsent(cmd.category, () => []).add(cmd);
   249→    }
   250→    return groups;
   251→  }
