   152→class _OiSearchState extends State<OiSearch> {
   153→  late TextEditingController _textController;
   154→  late FocusNode _inputFocusNode;
   155→  Timer? _debounceTimer;
   156→  bool _loading = false;
   157→  int _highlightedIndex = -1;
   158→  Map<String, List<OiSearchResult>> _resultsByCategory = {};
   159→  final List<OiSearchResult> _recentItems = [];
   160→  final Map<String, String> _activeFilters = {};
   161→
   162→  @override
   163→  void initState() {
   164→    super.initState();
   165→    _textController = TextEditingController();
   166→    _inputFocusNode = FocusNode(onKeyEvent: _handleKeyEvent);
   167→    WidgetsBinding.instance.addPostFrameCallback((_) {
   168→      if (mounted) _inputFocusNode.requestFocus();
   169→    });
   170→  }
   171→
   172→  @override
   173→  void dispose() {
   174→    _debounceTimer?.cancel();
   175→    _textController.dispose();
   176→    _inputFocusNode.dispose();
   177→    super.dispose();
   178→  }
   179→
   180→  // ── All results flattened ─────────────────────────────────────────────────
   181→
   182→  List<OiSearchResult> get _allResults {
   183→    final results = <OiSearchResult>[];
   184→    for (final source in widget.sources) {
   185→      final categoryResults = _resultsByCategory[source.category];
   186→      if (categoryResults != null) {
   187→        results.addAll(categoryResults.take(source.maxResults));
   188→      }
   189→    }
   190→    return results;
   191→  }
   192→
   193→  // ── Search ────────────────────────────────────────────────────────────────
   194→
   195→  void _onQueryChanged(String query) {
   196→    _debounceTimer?.cancel();
   197→    if (query.isEmpty) {
   198→      setState(() {
   199→        _resultsByCategory = {};
   200→        _highlightedIndex = -1;
   201→        _loading = false;
   202→      });
   203→      return;
   204→    }
   205→    _debounceTimer = Timer(widget.debounce, () => _performSearch(query));
   206→  }
   207→
   208→  Future<void> _performSearch(String query) async {
   209→    setState(() => _loading = true);
   210→
   211→    final results = <String, List<OiSearchResult>>{};
   212→    try {
   213→      final futures = widget.sources.map((source) async {
   214→        final sourceResults = await source.search(query);
   215→        return MapEntry(
   216→          source.category,
   217→          sourceResults.take(source.maxResults).toList(),
   218→        );
   219→      });
   220→
   221→      final entries = await Future.wait(futures);
   222→      for (final entry in entries) {
   223→        results[entry.key] = entry.value;
   224→      }
   225→    } on Exception {
   226→      // Silently handle search errors; results stay empty.
   227→    }
   228→
   229→    if (mounted) {
   230→      setState(() {
   231→        _resultsByCategory = results;
   232→        _loading = false;
   233→        _highlightedIndex = _allResults.isEmpty ? -1 : 0;
   234→      });
   235→    }
   236→  }
   237→
   238→  // ── Selection ─────────────────────────────────────────────────────────────
   239→
   240→  void _selectResult(OiSearchResult result) {
   241→    // Track in recents.
   242→    _recentItems
   243→      ..removeWhere((r) => r.id == result.id)
   244→      ..insert(0, result);
   245→    if (_recentItems.length > widget.maxRecent) {
   246→      _recentItems.removeRange(widget.maxRecent, _recentItems.length);
   247→    }
   248→
   249→    widget.onSelect?.call(result);
   250→  }
   251→
   252→  // ── Keyboard ──────────────────────────────────────────────────────────────
   253→
   254→  KeyEventResult _handleKeyEvent(FocusNode node, KeyEvent event) {
   255→    if (event is! KeyDownEvent && event is! KeyRepeatEvent) {
   256→      return KeyEventResult.ignored;
   257→    }
   258→
   259→    final results = _allResults;
   260→
   261→    if (event.logicalKey == LogicalKeyboardKey.arrowDown) {
   262→      setState(() {
   263→        _highlightedIndex =
   264→            (_highlightedIndex + 1).clamp(0, results.length - 1);
   265→      });
   266→      return KeyEventResult.handled;
   267→    }
   268→
   269→    if (event.logicalKey == LogicalKeyboardKey.arrowUp) {
   270→      setState(() {
   271→        _highlightedIndex =
   272→            (_highlightedIndex - 1).clamp(0, results.length - 1);
   273→      });
   274→      return KeyEventResult.handled;
   275→    }
   276→
   277→    if (event.logicalKey == LogicalKeyboardKey.enter) {
   278→      if (_highlightedIndex >= 0 && _highlightedIndex < results.length) {
   279→        _selectResult(results[_highlightedIndex]);
   280→      }
   281→      return KeyEventResult.handled;
   282→    }
   283→
   284→    if (event.logicalKey == LogicalKeyboardKey.escape) {
   285→      widget.onDismiss?.call();
   286→      return KeyEventResult.handled;
   287→    }
   288→
   289→    return KeyEventResult.ignored;
   290→  }
