   547→
   548→  Widget _buildResultTile(
   549→    BuildContext context,
   550→    OiSearchResult result,
   551→    List<OiSearchResult> allResults,
   552→  ) {
   553→    final colors = context.colors;
   554→    final index = allResults.indexOf(result);
   555→    final isHighlighted = index == _highlightedIndex;
   556→
   557→    return GestureDetector(
   558→      onTap: () => _selectResult(result),
   559→      behavior: HitTestBehavior.opaque,
   560→      child: Container(
   561→        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
   562→        color: isHighlighted ? colors.surfaceHover : null,
   563→        child: Row(
   564→          children: [
   565→            if (result.leading != null)
   566→              Padding(
   567→                padding: const EdgeInsets.only(right: 8),
   568→                child: result.leading,
   569→              ),
   570→            Expanded(
   571→              child: Column(
   572→                mainAxisSize: MainAxisSize.min,
   573→                crossAxisAlignment: CrossAxisAlignment.start,
   574→                children: [
   575→                  Text(
   576→                    result.title,
   577→                    style: TextStyle(fontSize: 14, color: colors.text),
   578→                    maxLines: 1,
   579→                    overflow: TextOverflow.ellipsis,
   580→                  ),
   581→                  if (result.subtitle != null)
   582→                    Text(
   583→                      result.subtitle!,
   584→                      style: TextStyle(fontSize: 12, color: colors.textMuted),
   585→                      maxLines: 1,
   586→                      overflow: TextOverflow.ellipsis,
   587→                    ),
   588→                ],
   589→              ),
   590→            ),
   591→            if (result.trailing != null) result.trailing!,
   592→          ],
   593→        ),
   594→      ),
   595→    );
   596→  }
