    15→List<OiSearchResult> _fileResults(String query) {
    16→  const items = [
    17→    OiSearchResult(id: 'f1', title: 'main.dart', subtitle: 'lib/'),
    18→    OiSearchResult(id: 'f2', title: 'pubspec.yaml', subtitle: 'root'),
    19→    OiSearchResult(id: 'f3', title: 'README.md', subtitle: 'root'),
    20→  ];
    21→  if (query.isEmpty) return items;
    22→  final lower = query.toLowerCase();
    23→  return items.where((r) => r.title.toLowerCase().contains(lower)).toList();
    24→}
    25→
    26→List<OiSearchResult> _commandResults(String query) {
    27→  const items = [
    28→    OiSearchResult(id: 'c1', title: 'Open File'),
    29→    OiSearchResult(id: 'c2', title: 'Save All'),
    30→    OiSearchResult(id: 'c3', title: 'Toggle Terminal'),
    31→  ];
    32→  if (query.isEmpty) return items;
    33→  final lower = query.toLowerCase();
    34→  return items.where((r) => r.title.toLowerCase().contains(lower)).toList();
    35→}
