    10→/// A searchable select box with type-ahead filtering.
    11→///
    12→/// The user types to filter options, and the dropdown shows matching results.
    13→/// Supports async search, multi-select, grouping, create-new, recent/favorite
    14→/// sections, virtualization, and pagination.
    15→///
    16→/// {@category Composites}
    17→class OiComboBox<T> extends StatefulWidget {
    18→  /// Creates an [OiComboBox].
    19→  const OiComboBox({
    20→    super.key,
    21→    required this.label,
    22→    required this.labelOf,
    23→    this.items = const [],
    24→    this.value,
    25→    this.onSelect,
    26→    this.search,
    27→    this.onCreate,
    28→    this.placeholder,
    29→    this.clearable = true,
    30→    this.enabled = true,
    31→    this.hint,
    32→    this.error,
    33→    this.multiSelect = false,
    34→    this.selectedValues = const [],
    35→    this.onMultiSelect,
    36→    this.maxChipsVisible,
    37→    this.groupBy,
    38→    this.groupOrder,
    39→    this.recentItems,
    40→    this.favoriteItems,
    41→    this.virtualScroll = false,
    42→    this.itemHeight,
    43→    this.loadMore,
    44→    this.moreAvailable = false,
    45→    this.optionBuilder,
    46→  });
    47→
    48→  /// Accessibility label for the combo box.
    49→  final String label;
    50→
    51→  /// Function to get display label from an item.
    52→  final String Function(T) labelOf;
    53→
    54→  /// Static list of items.
    55→  final List<T> items;
    56→
    57→  /// Currently selected value (single-select mode).
    58→  final T? value;
    59→
    60→  /// Called when an item is selected or cleared (single-select mode).
    61→  ///
    62→  /// When the selection is cleared, `null` is passed.
    63→  final ValueChanged<T?>? onSelect;
    64→
    65→  /// Async search function. Overrides [items] filtering when provided.
    66→  final Future<List<T>> Function(String query)? search;
    67→
    68→  /// Called when the user types a value that doesn't match any option.
    69→  final ValueChanged<String>? onCreate;
    70→
    71→  /// Placeholder text when no value is selected.
    72→  final String? placeholder;
    73→
    74→  /// Whether the selection can be cleared.
    75→  final bool clearable;
    76→
    77→  /// Whether the combo box is enabled.
    78→  final bool enabled;
    79→
    80→  /// Hint text below the input.
    81→  final String? hint;
    82→
    83→  /// Error text below the input (replaces hint).
    84→  final String? error;
    85→
    86→  /// Whether multi-select mode is enabled.
    87→  final bool multiSelect;
    88→
    89→  /// Currently selected values (multi-select mode).
    90→  final List<T> selectedValues;
    91→
    92→  /// Called when selection changes (multi-select mode).
    93→  final ValueChanged<List<T>>? onMultiSelect;
    94→
    95→  /// Maximum number of chips visible in multi-select trigger.
    96→  final int? maxChipsVisible;
    97→
    98→  /// Function to group options under headers.
    99→  final String Function(T)? groupBy;
   100→
   101→  /// Order of group headers.
   102→  final List<String>? groupOrder;
   103→
   104→  /// Recent items shown in a dedicated section.
   105→  final List<T>? recentItems;
   106→
   107→  /// Favorite items shown in a dedicated section.
   108→  final List<T>? favoriteItems;
   109→
   110→  /// Whether to use virtualized scrolling for large option lists.
   111→  final bool virtualScroll;
   112→
   113→  /// Item height for virtualized scrolling.
   114→  final double? itemHeight;
   115→
   116→  /// Callback to load more items (pagination).
   117→  final Future<List<T>> Function()? loadMore;
   118→
   119→  /// Whether there are more items to load.
   120→  final bool moreAvailable;
   121→
   122→  /// Custom option builder.
   123→  final Widget Function(
   124→    T, {
   125→    required bool highlighted,
   126→    required bool selected,
   127→  })? optionBuilder;
   128→
   129→  @override
   130→  State<OiComboBox<T>> createState() => _OiComboBoxState<T>();
   131→}
   132→
   133→class _OiComboBoxState<T> extends State<OiComboBox<T>> {
   134→  late TextEditingController _textController;
   135→  late FocusNode _inputFocusNode;
   136→  bool _open = false;
   137→  int _highlightedIndex = -1;
   138→  List<T> _filteredItems = [];
   139→  List<T> _asyncResults = [];
   140→  bool _loading = false;
   141→  Timer? _debounce;
   142→
   143→  @override
   144→  void initState() {
   145→    super.initState();
   146→    _textController = TextEditingController();
   147→    _inputFocusNode = FocusNode(onKeyEvent: _handleKeyEvent);
   148→    _filteredItems = List<T>.from(widget.items);
   149→  }
   150→
   151→  @override
   152→  void didUpdateWidget(OiComboBox<T> oldWidget) {
   153→    super.didUpdateWidget(oldWidget);
   154→    if (oldWidget.items != widget.items) {
   155→      _applyFilter(_textController.text);
   156→    }
   157→  }
   158→
   159→  @override
   160→  void dispose() {
   161→    _debounce?.cancel();
   162→    _textController.dispose();
   163→    _inputFocusNode.dispose();
   164→    super.dispose();
   165→  }
   166→
   167→  // ── Filtering ─────────────────────────────────────────────────────────────
   168→
   169→  void _applyFilter(String query) {
   170→    if (widget.search != null) {
   171→      _debounce?.cancel();
   172→      _debounce = Timer(const Duration(milliseconds: 200), () {
   173→        _performAsyncSearch(query);
   174→      });
   175→      return;
   176→    }
   177→
   178→    final lower = query.toLowerCase();
   179→    setState(() {
   180→      if (query.isEmpty) {
   181→        _filteredItems = List<T>.from(widget.items);
   182→      } else {
   183→        _filteredItems = widget.items
   184→            .where((item) =>
   185→                widget.labelOf(item).toLowerCase().contains(lower))
   186→            .toList();
   187→      }
   188→      _highlightedIndex =
   189→          _filteredItems.isEmpty ? -1 : 0;
   190→    });
   191→  }
   192→
   193→  Future<void> _performAsyncSearch(String query) async {
   194→    setState(() => _loading = true);
   195→    try {
   196→      final results = await widget.search!(query);
   197→      if (mounted) {
   198→        setState(() {
   199→          _asyncResults = results;
   200→          _filteredItems = results;
   201→          _loading = false;
   202→          _highlightedIndex =
   203→              _filteredItems.isEmpty ? -1 : 0;
   204→        });
   205→      }
   206→    } on Exception {
   207→      if (mounted) {
   208→        setState(() {
   209→          _loading = false;
   210→          _filteredItems = [];
   211→          _asyncResults = [];
   212→        });
   213→      }
   214→    }
   215→  }
   216→
   217→  // ── Effective items list ──────────────────────────────────────────────────
   218→
   219→  List<T> get _effectiveItems {
   220→    if (widget.search != null) return _asyncResults;
   221→    return _filteredItems;
   222→  }
   223→
   224→  // ── Grouped items ─────────────────────────────────────────────────────────
   225→
   226→  /// Returns items organized into groups (with headers) if [groupBy] is set.
   227→  List<_GroupedSection<T>> _buildGroupedSections() {
   228→    final items = _effectiveItems;
   229→    if (widget.groupBy == null) {
   230→      return [_GroupedSection<T>(header: null, items: items)];
   231→    }
   232→
   233→    final groups = <String, List<T>>{};
   234→    for (final item in items) {
   235→      final key = widget.groupBy!(item);
   236→      groups.putIfAbsent(key, () => []).add(item);
   237→    }
   238→
   239→    final order = widget.groupOrder;
   240→    final keys = order != null
   241→        ? order.where(groups.containsKey).toList()
   242→        : groups.keys.toList();
   243→
   244→    return keys
   245→        .map((k) => _GroupedSection<T>(header: k, items: groups[k]!))
   246→        .toList();
   247→  }
   248→
   249→  // ── Open / Close ──────────────────────────────────────────────────────────
   250→
   251→  void _openDropdown() {
   252→    if (!widget.enabled) return;
   253→    _textController.clear();
   254→    _applyFilter('');
   255→    setState(() {
   256→      _open = true;
   257→      _highlightedIndex =
   258→          _filteredItems.isEmpty ? -1 : 0;
   259→    });
   260→    WidgetsBinding.instance.addPostFrameCallback((_) {
   261→      if (mounted) _inputFocusNode.requestFocus();
   262→    });
   263→  }
   264→
   265→  void _closeDropdown() {
   266→    setState(() => _open = false);
   267→    _textController.clear();
   268→  }
   269→
   270→  // ── Selection ─────────────────────────────────────────────────────────────
   271→
   272→  void _selectItem(T item) {
   273→    if (widget.multiSelect) {
   274→      final current = List<T>.from(widget.selectedValues);
   275→      if (current.contains(item)) {
   276→        current.remove(item);
   277→      } else {
   278→        current.add(item);
   279→      }
   280→      widget.onMultiSelect?.call(current);
   281→      // Keep dropdown open in multi-select mode.
   282→      return;
   283→    }
   284→
   285→    widget.onSelect?.call(item);
   286→    _closeDropdown();
   287→  }
   288→
   289→  void _clearSelection() {
   290→    if (widget.multiSelect) {
   291→      widget.onMultiSelect?.call([]);
   292→    } else {
   293→      widget.onSelect?.call(null);
   294→    }
   295→  }
   296→
   297→  bool _isSelected(T item) {
   298→    if (widget.multiSelect) {
   299→      return widget.selectedValues.contains(item);
   300→    }
   301→    return widget.value == item;
   302→  }
   303→
   304→  // ── Keyboard ──────────────────────────────────────────────────────────────
   305→
   306→  KeyEventResult _handleKeyEvent(FocusNode node, KeyEvent event) {
   307→    if (event is! KeyDownEvent && event is! KeyRepeatEvent) {
   308→      return KeyEventResult.ignored;
   309→    }
   310→
   311→    final items = _effectiveItems;
   312→
   313→    if (event.logicalKey == LogicalKeyboardKey.arrowDown) {
   314→      setState(() {
   315→        _highlightedIndex = (_highlightedIndex + 1).clamp(0, items.length - 1);
   316→      });
   317→      return KeyEventResult.handled;
   318→    }
   319→
   320→    if (event.logicalKey == LogicalKeyboardKey.arrowUp) {
   321→      setState(() {
   322→        _highlightedIndex = (_highlightedIndex - 1).clamp(0, items.length - 1);
   323→      });
   324→      return KeyEventResult.handled;
   325→    }
   326→
   327→    if (event.logicalKey == LogicalKeyboardKey.enter) {
   328→      if (_highlightedIndex >= 0 && _highlightedIndex < items.length) {
   329→        _selectItem(items[_highlightedIndex]);
   330→      } else if (widget.onCreate != null && _textController.text.isNotEmpty) {
   331→        widget.onCreate!(_textController.text);
   332→        _closeDropdown();
   333→      }
   334→      return KeyEventResult.handled;
   335→    }
   336→
   337→    if (event.logicalKey == LogicalKeyboardKey.escape) {
   338→      _closeDropdown();
   339→      return KeyEventResult.handled;
   340→    }
   341→
   342→    return KeyEventResult.ignored;
   343→  }
   344→
   345→  // ── Build dropdown ────────────────────────────────────────────────────────
   346→
   347→  Widget _buildDropdown(BuildContext context) {
   348→    final colors = context.colors;
   349→    const itemHeight = 40.0;
   350→    final effectiveItemHeight = widget.itemHeight ?? itemHeight;
   351→    final items = _effectiveItems;
   352→
   353→    final sections = _buildGroupedSections();
   354→    final hasRecent =
   355→        widget.recentItems != null && widget.recentItems!.isNotEmpty;
   356→    final hasFavorite =
   357→        widget.favoriteItems != null && widget.favoriteItems!.isNotEmpty;
   358→
   359→    return UnconstrainedBox(
   360→      alignment: Alignment.topLeft,
   361→      child: Container(
   362→        width: 280,
   363→        constraints: const BoxConstraints(maxHeight: 300),
   364→        decoration: BoxDecoration(
   365→          color: colors.surface,
   366→          borderRadius: BorderRadius.circular(8),
   367→          boxShadow: [
   368→            BoxShadow(
   369→              color: colors.overlay,
   370→              blurRadius: 12,
   371→              offset: const Offset(0, 4),
   372→            ),
   373→          ],
   374→        ),
   375→        child: Column(
   376→          mainAxisSize: MainAxisSize.min,
   377→          children: [
   378→            // Search input
   379→            Padding(
   380→              padding: const EdgeInsets.all(8),
   381→              child: OiRawInput(
   382→                controller: _textController,
   383→                focusNode: _inputFocusNode,
   384→                placeholder: 'Search\u2026',
   385→                onChanged: _applyFilter,
   386→              ),
   387→            ),
   388→            // Loading state
   389→            if (_loading)
   390→              Padding(
   391→                padding: const EdgeInsets.all(12),
   392→                child: Text(
   393→                  'Loading\u2026',
   394→                  style: TextStyle(color: colors.textMuted, fontSize: 14),
   395→                ),
   396→              )
   397→            // Empty state
   398→            else if (items.isEmpty && !hasRecent && !hasFavorite)
   399→              Padding(
   400→                padding: const EdgeInsets.all(12),
   401→                child: Wrap(
   402→                  alignment: WrapAlignment.center,
   403→                  spacing: 8,
   404→                  runSpacing: 4,
   405→                  children: [
   406→                    Text(
   407→                      'No results',
   408→                      style:
   409→                          TextStyle(color: colors.textMuted, fontSize: 14),
   410→                    ),
   411→                    if (widget.onCreate != null &&
   412→                        _textController.text.isNotEmpty)
   413→                      GestureDetector(
   414→                        onTap: () {
   415→                          widget.onCreate!(_textController.text);
   416→                          _closeDropdown();
   417→                        },
   418→                        child: Text(
   419→                          'Create "${_textController.text}"',
   420→                          style: TextStyle(
   421→                            color: colors.primary.base,
   422→                            fontSize: 14,
   423→                          ),
   424→                          overflow: TextOverflow.ellipsis,
   425→                        ),
   426→                      ),
   427→                  ],
   428→                ),
   429→              )
   430→            // Items list
   431→            else
   432→              Flexible(
   433→                child: SingleChildScrollView(
   434→                  child: Column(
   435→                    mainAxisSize: MainAxisSize.min,
   436→                    crossAxisAlignment: CrossAxisAlignment.stretch,
   437→                    children: [
   438→                      // Recent section
   439→                      if (hasRecent) ...[
   440→                        _buildSectionHeader(context, 'Recent'),
   441→                        ...widget.recentItems!.map(
   442→                          (item) => _buildOptionTile(
   443→                            context,
   444→                            item,
   445→                            effectiveItemHeight,
   446→                          ),
   447→                        ),
   448→                      ],
   449→                      // Favorites section
   450→                      if (hasFavorite) ...[
   451→                        _buildSectionHeader(context, 'Favorites'),
   452→                        ...widget.favoriteItems!.map(
   453→                          (item) => _buildOptionTile(
   454→                            context,
   455→                            item,
   456→                            effectiveItemHeight,
   457→                          ),
   458→                        ),
   459→                      ],
   460→                      // Main sections (possibly grouped)
   461→                      for (final section in sections) ...[
   462→                        if (section.header != null)
   463→                          _buildSectionHeader(context, section.header!),
   464→                        ...section.items.map(
   465→                          (item) => _buildOptionTile(
   466→                            context,
   467→                            item,
   468→                            effectiveItemHeight,
   469→                          ),
   470→                        ),
   471→                      ],
   472→                      // Load more
   473→                      if (widget.moreAvailable && widget.loadMore != null)
   474→                        GestureDetector(
   475→                          onTap: () async {
   476→                            final more = await widget.loadMore!();
   477→                            if (mounted) {
   478→                              setState(() {
   479→                                _filteredItems.addAll(more);
   480→                                _asyncResults.addAll(more);
   481→                              });
   482→                            }
   483→                          },
   484→                          child: Container(
   485→                            height: effectiveItemHeight,
   486→                            alignment: Alignment.center,
   487→                            child: Text(
   488→                              'Load more\u2026',
   489→                              style: TextStyle(
   490→                                color: colors.primary.base,
   491→                                fontSize: 14,
   492→                              ),
   493→                            ),
   494→                          ),
   495→                        ),
   496→                    ],
   497→                  ),
   498→                ),
   499→              ),
   500→          ],
   501→        ),
   502→      ),
   503→    );
   504→  }
   505→
   506→  Widget _buildSectionHeader(BuildContext context, String title) {
   507→    final colors = context.colors;
   508→    return Padding(
   509→      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 4),
   510→      child: Text(
   511→        title,
   512→        style: TextStyle(
   513→          fontSize: 11,
   514→          fontWeight: FontWeight.w600,
   515→          color: colors.textMuted,
   516→        ),
   517→      ),
   518→    );
   519→  }
   520→
   521→  Widget _buildOptionTile(
   522→    BuildContext context,
   523→    T item,
   524→    double height,
   525→  ) {
   526→    final colors = context.colors;
   527→    final items = _effectiveItems;
   528→    final index = items.indexOf(item);
   529→    final isHighlighted = index == _highlightedIndex;
   530→    final selected = _isSelected(item);
   531→
   532→    if (widget.optionBuilder != null) {
   533→      return GestureDetector(
   534→        onTap: () => _selectItem(item),
   535→        behavior: HitTestBehavior.opaque,
   536→        child: widget.optionBuilder!(
   537→          item,
   538→          highlighted: isHighlighted,
   539→          selected: selected,
   540→        ),
   541→      );
   542→    }
   543→
   544→    return GestureDetector(
   545→      onTap: () => _selectItem(item),
   546→      behavior: HitTestBehavior.opaque,
   547→      child: Container(
   548→        height: height,
   549→        padding: const EdgeInsets.symmetric(horizontal: 12),
   550→        color: isHighlighted
   551→            ? colors.surfaceHover
   552→            : selected
   553→                ? colors.primary.base.withValues(alpha: 0.08)
   554→                : null,
   555→        child: Row(
   556→          children: [
   557→            if (widget.multiSelect)
   558→              Padding(
   559→                padding: const EdgeInsets.only(right: 8),
   560→                child: _OiCheckMark(checked: selected),
   561→              ),
   562→            Expanded(
   563→              child: Text(
   564→                widget.labelOf(item),
   565→                style: TextStyle(
   566→                  fontSize: 14,
   567→                  color: selected ? colors.primary.base : colors.text,
   568→                ),
   569→                maxLines: 1,
   570→                overflow: TextOverflow.ellipsis,
   571→              ),
   572→            ),
   573→          ],
   574→        ),
   575→      ),
   576→    );
   577→  }
   578→
   579→  // ── Build trigger ─────────────────────────────────────────────────────────
   580→
   581→  Widget _buildTrigger(BuildContext context) {
   582→    final colors = context.colors;
   583→
   584→    // Multi-select: show chips
   585→    if (widget.multiSelect && widget.selectedValues.isNotEmpty) {
   586→      final visible = widget.maxChipsVisible ?? widget.selectedValues.length;
   587→      final visibleItems = widget.selectedValues.take(visible).toList();
   588→      final remaining = widget.selectedValues.length - visible;
   589→
   590→      return Row(
   591→        children: [
   592→          Expanded(
   593→            child: Wrap(
   594→              spacing: 4,
   595→              runSpacing: 2,
   596→              children: [
   597→                for (final item in visibleItems)
   598→                  Container(
   599→                    padding:
   600→                        const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
   601→                    decoration: BoxDecoration(
   602→                      color: colors.surfaceActive,
   603→                      borderRadius: BorderRadius.circular(4),
   604→                    ),
   605→                    child: Text(
   606→                      widget.labelOf(item),
   607→                      style: TextStyle(fontSize: 12, color: colors.text),
   608→                    ),
   609→                  ),
   610→                if (remaining > 0)
   611→                  Text(
   612→                    '+$remaining',
   613→                    style: TextStyle(fontSize: 12, color: colors.textMuted),
   614→                  ),
   615→              ],
   616→            ),
   617→          ),
   618→          if (widget.clearable)
   619→            GestureDetector(
   620→              onTap: _clearSelection,
   621→              child: Padding(
   622→                padding: const EdgeInsets.only(left: 4),
   623→                child: Icon(
   624→                  const IconData(0xe5cd, fontFamily: 'MaterialIcons'),
   625→                  size: 16,
   626→                  color: colors.textMuted,
   627→                ),
   628→              ),
   629→            ),
   630→        ],
   631→      );
   632→    }
   633→
   634→    // Single-select: show selected label or placeholder
   635→    final hasValue = widget.value != null;
   636→    final displayText = hasValue
   637→        ? widget.labelOf(widget.value as T)
   638→        : widget.placeholder ?? '';
   639→
   640→    return Row(
   641→      children: [
   642→        Expanded(
   643→          child: Text(
   644→            displayText,
   645→            style: TextStyle(
   646→              fontSize: 14,
   647→              color: hasValue ? colors.text : colors.textMuted,
   648→            ),
   649→            maxLines: 1,
   650→            overflow: TextOverflow.ellipsis,
   651→          ),
   652→        ),
   653→        if (hasValue && widget.clearable)
   654→          GestureDetector(
   655→            onTap: _clearSelection,
   656→            child: Padding(
   657→              padding: const EdgeInsets.only(left: 4),
   658→              child: Icon(
   659→                const IconData(0xe5cd, fontFamily: 'MaterialIcons'),
   660→                size: 16,
   661→                color: colors.textMuted,
   662→              ),
   663→            ),
   664→          ),
   665→      ],
   666→    );
   667→  }
   668→
   669→  // ── Build ─────────────────────────────────────────────────────────────────
   670→
   671→  @override
   672→  Widget build(BuildContext context) {
   673→    final colors = context.colors;
   674→
   675→    final chevron = Icon(
   676→      const IconData(0xe5c5, fontFamily: 'MaterialIcons'),
   677→      size: 16,
   678→      color: colors.textMuted,
   679→    );
   680→
   681→    final anchor = Semantics(
   682→      label: widget.label,
   683→      enabled: widget.enabled,
   684→      child: GestureDetector(
   685→        onTap: widget.enabled ? _openDropdown : null,
   686→        behavior: HitTestBehavior.opaque,
   687→        child: OiInputFrame(
   688→          label: widget.label,
   689→          hint: widget.hint,
   690→          error: widget.error,
   691→          focused: _open,
   692→          enabled: widget.enabled,
   693→          trailing: chevron,
   694→          child: _buildTrigger(context),
   695→        ),
   696→      ),
   697→    );
   698→
   699→    return OiFloating(
   700→      visible: _open,
   701→      anchor: anchor,
   702→      child: _buildDropdown(context),
   703→    );
   704→  }
   705→}
   706→
   707→// ── Internal helpers ──────────────────────────────────────────────────────────
   708→
   709→/// A grouped section with an optional header and a list of items.
   710→class _GroupedSection<T> {
   711→  /// Creates a [_GroupedSection].
   712→  const _GroupedSection({required this.header, required this.items});
   713→
   714→  /// The section header text, or null for the default section.
   715→  final String? header;
   716→
   717→  /// The items in this section.
   718→  final List<T> items;
   719→}
   720→
   721→/// A simple check mark indicator for multi-select mode.
   722→class _OiCheckMark extends StatelessWidget {
   723→  const _OiCheckMark({required this.checked});
   724→
   725→  final bool checked;
   726→
   727→  @override
   728→  Widget build(BuildContext context) {
   729→    final colors = context.colors;
   730→    return Container(
   731→      width: 16,
   732→      height: 16,
   733→      decoration: BoxDecoration(
   734→        borderRadius: BorderRadius.circular(3),
   735→        border: Border.all(
   736→          color: checked ? colors.primary.base : colors.border,
   737→        ),
   738→        color: checked ? colors.primary.base : null,
   739→      ),
   740→      child: checked
   741→          ? Icon(
   742→              const IconData(0xe5ca, fontFamily: 'MaterialIcons'),
   743→              size: 12,
   744→              color: colors.textOnPrimary,
   745→            )
   746→          : null,
   747→    );
   748→  }
   749→}
