    62→/// A command palette for quick access to actions via fuzzy search.
    63→///
    64→/// VS Code/Raycast-style command bar with fuzzy search, nested commands,
    65→/// keyboard shortcut display, and category grouping.
    66→///
    67→/// {@category Composites}
    68→class OiCommandBar extends StatefulWidget {
    69→  /// Creates an [OiCommandBar].
    70→  const OiCommandBar({
    71→    super.key,
    72→    required this.commands,
    73→    this.onDismiss,
    74→    this.showRecent = true,
    75→    this.fuzzySearch = true,
    76→    this.previewBuilder,
    77→    this.contextCommands,
    78→    required this.label,
    79→  });
    80→
    81→  /// The list of available commands.
    82→  final List<OiCommand> commands;
    83→
    84→  /// Called when the user dismisses the command bar.
    85→  final VoidCallback? onDismiss;
    86→
    87→  /// Whether to show recent commands when the query is empty.
    88→  final bool showRecent;
    89→
    90→  /// Whether to use fuzzy matching instead of substring matching.
    91→  final bool fuzzySearch;
    92→
    93→  /// Optional builder for a preview pane for the highlighted command.
    94→  final Widget Function(OiCommand)? previewBuilder;
    95→
    96→  /// Optional function to provide context-specific commands.
    97→  final List<OiCommand> Function(BuildContext)? contextCommands;
    98→
    99→  /// Accessibility label for the command bar.
   100→  final String label;
   101→
   102→  @override
   103→  State<OiCommandBar> createState() => _OiCommandBarState();
   104→}
   105→
   106→class _OiCommandBarState extends State<OiCommandBar> {
   107→  late TextEditingController _textController;
   108→  late FocusNode _inputFocusNode;
   109→  int _highlightedIndex = 0;
   110→  List<OiCommand> _filteredCommands = [];
   111→  final List<OiCommand> _recentCommands = [];
   112→  List<OiCommand>? _commandStack;
   113→  String? _parentLabel;
   114→
   115→  @override
   116→  void initState() {
   117→    super.initState();
   118→    _textController = TextEditingController();
   119→    _inputFocusNode = FocusNode(onKeyEvent: _handleKeyEvent);
   120→    _filteredCommands = _sortedCommands(widget.commands);
   121→    WidgetsBinding.instance.addPostFrameCallback((_) {
   122→      if (mounted) _inputFocusNode.requestFocus();
   123→    });
   124→  }
   125→
   126→  @override
   127→  void didUpdateWidget(OiCommandBar oldWidget) {
   128→    super.didUpdateWidget(oldWidget);
   129→    if (oldWidget.commands != widget.commands) {
   130→      _applyFilter(_textController.text);
   131→    }
   132→  }
   133→
   134→  @override
   135→  void dispose() {
   136→    _textController.dispose();
   137→    _inputFocusNode.dispose();
   138→    super.dispose();
   139→  }
   140→
   141→  // ── Active command list ───────────────────────────────────────────────────
   142→
   143→  List<OiCommand> get _activeCommands => _commandStack ?? widget.commands;
   144→
   145→  // ── Sorting ───────────────────────────────────────────────────────────────
   146→
   147→  List<OiCommand> _sortedCommands(List<OiCommand> commands) {
   148→    return List<OiCommand>.from(commands)
   149→      ..sort((a, b) => b.priority.compareTo(a.priority));
   150→  }
   151→
   152→  // ── Filtering ─────────────────────────────────────────────────────────────
   153→
   154→  void _applyFilter(String query) {
   155→    setState(() {
   156→      if (query.isEmpty) {
   157→        _filteredCommands = _sortedCommands(_activeCommands);
   158→      } else if (widget.fuzzySearch) {
   159→        _filteredCommands = _fuzzyFilter(_activeCommands, query);
   160→      } else {
   161→        _filteredCommands = _substringFilter(_activeCommands, query);
   162→      }
   163→      _highlightedIndex =
   164→          _filteredCommands.isEmpty ? -1 : 0;
   165→    });
   166→  }
   167→
   168→  List<OiCommand> _substringFilter(List<OiCommand> commands, String query) {
   169→    final lower = query.toLowerCase();
   170→    return _sortedCommands(
   171→      commands.where((cmd) {
   172→        final matchLabel = cmd.label.toLowerCase().contains(lower);
   173→        final matchDesc =
   174→            cmd.description?.toLowerCase().contains(lower) ?? false;
   175→        final matchKeywords =
   176→            cmd.keywords.any((k) => k.toLowerCase().contains(lower));
   177→        return matchLabel || matchDesc || matchKeywords;
   178→      }).toList(),
   179→    );
   180→  }
   181→
   182→  List<OiCommand> _fuzzyFilter(List<OiCommand> commands, String query) {
   183→    final lower = query.toLowerCase();
   184→    final scored = <(OiCommand, int)>[];
   185→
   186→    for (final cmd in commands) {
   187→      final score = _fuzzyScore(cmd, lower);
   188→      if (score > 0) {
   189→        scored.add((cmd, score));
   190→      }
   191→    }
   192→
   193→    scored.sort((a, b) {
   194→      // Higher score first, then higher priority.
   195→      final cmp = b.$2.compareTo(a.$2);
   196→      if (cmp != 0) return cmp;
   197→      return b.$1.priority.compareTo(a.$1.priority);
   198→    });
   199→
   200→    return scored.map((e) => e.$1).toList();
   201→  }
   202→
   203→  /// Returns a positive score if [query] fuzzy-matches against [cmd],
   204→  /// or 0 if there is no match.
   205→  int _fuzzyScore(OiCommand cmd, String query) {
   206→    final targets = [
   207→      cmd.label.toLowerCase(),
   208→      if (cmd.description != null) cmd.description!.toLowerCase(),
   209→      ...cmd.keywords.map((k) => k.toLowerCase()),
   210→    ];
   211→
   212→    var bestScore = 0;
   213→    for (final target in targets) {
   214→      final score = _fuzzyMatchScore(target, query);
   215→      if (score > bestScore) bestScore = score;
   216→    }
   217→    return bestScore;
   218→  }
   219→
   220→  /// Simple fuzzy match: checks if all characters of [query] appear in
   221→  /// [target] in order. Returns a score based on how closely they match.
   222→  int _fuzzyMatchScore(String target, String query) {
   223→    var qi = 0;
   224→    var score = 0;
   225→    var lastMatchIndex = -1;
   226→
   227→    for (var ti = 0; ti < target.length && qi < query.length; ti++) {
   228→      if (target[ti] == query[qi]) {
   229→        score += 1;
   230→        // Bonus for consecutive matches.
   231→        if (lastMatchIndex == ti - 1) score += 2;
   232→        // Bonus for word boundary matches.
   233→        if (ti == 0 || target[ti - 1] == ' ') score += 3;
   234→        lastMatchIndex = ti;
   235→        qi++;
   236→      }
   237→    }
   238→
   239→    // All query characters must be found.
   240→    return qi == query.length ? score : 0;
   241→  }
   242→
   243→  // ── Grouped display ───────────────────────────────────────────────────────
   244→
   245→  Map<String?, List<OiCommand>> get _grouped {
   246→    final groups = <String?, List<OiCommand>>{};
   247→    for (final cmd in _filteredCommands) {
   248→      groups.putIfAbsent(cmd.category, () => []).add(cmd);
   249→    }
   250→    return groups;
   251→  }
   252→
   253→  // ── Drill-down ────────────────────────────────────────────────────────────
   254→
   255→  void _drillDown(OiCommand cmd) {
   256→    if (cmd.children != null && cmd.children!.isNotEmpty) {
   257→      setState(() {
   258→        _commandStack = cmd.children;
   259→        _parentLabel = cmd.label;
   260→        _textController.clear();
   261→        _filteredCommands = _sortedCommands(cmd.children!);
   262→        _highlightedIndex =
   263→            _filteredCommands.isEmpty ? -1 : 0;
   264→      });
   265→      return;
   266→    }
   267→
   268→    _executeCommand(cmd);
   269→  }
   270→
   271→  void _goBack() {
   272→    setState(() {
   273→      _commandStack = null;
   274→      _parentLabel = null;
   275→      _textController.clear();
   276→      _filteredCommands = _sortedCommands(widget.commands);
   277→      _highlightedIndex =
   278→          _filteredCommands.isEmpty ? -1 : 0;
   279→    });
   280→  }
   281→
   282→  // ── Execution ─────────────────────────────────────────────────────────────
   283→
   284→  void _executeCommand(OiCommand cmd) {
   285→    // Track recent.
   286→    _recentCommands
   287→      ..removeWhere((c) => c.id == cmd.id)
   288→      ..insert(0, cmd);
   289→    if (_recentCommands.length > 10) {
   290→      _recentCommands.removeRange(10, _recentCommands.length);
   291→    }
   292→
   293→    cmd.onExecute?.call();
   294→  }
   295→
   296→  // ── Keyboard ──────────────────────────────────────────────────────────────
   297→
   298→  KeyEventResult _handleKeyEvent(FocusNode node, KeyEvent event) {
   299→    if (event is! KeyDownEvent && event is! KeyRepeatEvent) {
   300→      return KeyEventResult.ignored;
   301→    }
   302→
   303→    if (event.logicalKey == LogicalKeyboardKey.arrowDown) {
   304→      setState(() {
   305→        _highlightedIndex =
   306→            (_highlightedIndex + 1).clamp(0, _filteredCommands.length - 1);
   307→      });
   308→      return KeyEventResult.handled;
   309→    }
   310→
   311→    if (event.logicalKey == LogicalKeyboardKey.arrowUp) {
   312→      setState(() {
   313→        _highlightedIndex =
   314→            (_highlightedIndex - 1).clamp(0, _filteredCommands.length - 1);
   315→      });
   316→      return KeyEventResult.handled;
   317→    }
   318→
   319→    if (event.logicalKey == LogicalKeyboardKey.enter) {
   320→      if (_highlightedIndex >= 0 &&
   321→          _highlightedIndex < _filteredCommands.length) {
   322→        _drillDown(_filteredCommands[_highlightedIndex]);
   323→      }
   324→      return KeyEventResult.handled;
   325→    }
   326→
   327→    if (event.logicalKey == LogicalKeyboardKey.escape) {
   328→      if (_commandStack != null) {
   329→        _goBack();
   330→      } else {
   331→        widget.onDismiss?.call();
   332→      }
   333→      return KeyEventResult.handled;
   334→    }
   335→
   336→    if (event.logicalKey == LogicalKeyboardKey.backspace &&
   337→        _textController.text.isEmpty &&
   338→        _commandStack != null) {
   339→      _goBack();
   340→      return KeyEventResult.handled;
   341→    }
   342→
   343→    return KeyEventResult.ignored;
   344→  }
   345→
   346→  // ── Shortcut display ──────────────────────────────────────────────────────
   347→
   348→  /// Formats a [ShortcutActivator] into a human-readable string.
   349→  String _formatShortcut(ShortcutActivator activator) {
   350→    if (activator is SingleActivator) {
   351→      final parts = <String>[];
   352→      if (activator.control) parts.add('Ctrl');
   353→      if (activator.meta) parts.add('\u2318');
   354→      if (activator.alt) parts.add('Alt');
   355→      if (activator.shift) parts.add('Shift');
   356→      parts.add(activator.trigger.keyLabel);
   357→      return parts.join('+');
   358→    }
   359→    return activator.toString();
   360→  }
   361→
   362→  // ── Build ─────────────────────────────────────────────────────────────────
   363→
   364→  @override
   365→  Widget build(BuildContext context) {
   366→    final colors = context.colors;
   367→    final grouped = _grouped;
   368→    final highlightedCommand = _highlightedIndex >= 0 &&
   369→            _highlightedIndex < _filteredCommands.length
   370→        ? _filteredCommands[_highlightedIndex]
   371→        : null;
   372→
   373→    return Semantics(
   374→      container: true,
   375→      explicitChildNodes: true,
   376→      label: widget.label,
   377→      child: Container(
   378→        width: widget.previewBuilder != null ? 640 : 480,
   379→        constraints: const BoxConstraints(maxHeight: 420),
   380→        decoration: BoxDecoration(
   381→          color: colors.surface,
   382→          borderRadius: BorderRadius.circular(12),
   383→          boxShadow: [
   384→            BoxShadow(
   385→              color: colors.overlay,
   386→              blurRadius: 24,
   387→              offset: const Offset(0, 8),
   388→            ),
   389→          ],
   390→        ),
   391→        child: Column(
   392→          mainAxisSize: MainAxisSize.min,
   393→          children: [
   394→            // Input area
   395→            Padding(
   396→              padding: const EdgeInsets.all(12),
   397→              child: Row(
   398→                children: [
   399→                  // Back button when drilled down
   400→                  if (_commandStack != null) ...[
   401→                    GestureDetector(
   402→                      onTap: _goBack,
   403→                      child: Container(
   404→                        padding: const EdgeInsets.symmetric(
   405→                          horizontal: 6,
   406→                          vertical: 2,
   407→                        ),
   408→                        decoration: BoxDecoration(
   409→                          color: colors.surfaceActive,
   410→                          borderRadius: BorderRadius.circular(4),
   411→                        ),
   412→                        child: Text(
   413→                          _parentLabel ?? 'Back',
   414→                          style:
   415→                              TextStyle(fontSize: 12, color: colors.text),
   416→                        ),
   417→                      ),
   418→                    ),
   419→                    const SizedBox(width: 8),
   420→                  ],
   421→                  Expanded(
   422→                    child: OiRawInput(
   423→                      controller: _textController,
   424→                      focusNode: _inputFocusNode,
   425→                      placeholder: _commandStack != null
   426→                          ? 'Search in ${_parentLabel ?? "submenu"}\u2026'
   427→                          : 'Type a command\u2026',
   428→                      onChanged: _applyFilter,
   429→                      leading: Padding(
   430→                        padding: const EdgeInsets.only(right: 8),
   431→                        child: Icon(
   432→                          const IconData(
   433→                            0xe5c5,
   434→                            fontFamily: 'MaterialIcons',
   435→                          ),
